def pre(i):
    """
    Validates the input tuple i.
    i must be a tuple of length 3: (count, limit, rolled)
    - count: non‑negative integer
    - limit: non‑negative integer
    - rolled: boolean
    """
    if not isinstance(i, tuple) or len(i) != 3:
        return False
    count, limit, rolled = i
    if not (isinstance(count, int) and count >= 0):
        return False
    if not (isinstance(limit, int) and limit >= 0):
        return False
    if not isinstance(rolled, bool):
        return False
    return True


def post(i, o):
    """
    Checks that the output o is correct for the valid input i.
    - o must be a boolean.
    - If rolled is True (window just rolled over), a request is always allowed (o must be True).
    - Otherwise, a request is allowed iff count < limit.
    """
    if not pre(i):
        return False
    if not isinstance(o, bool):
        return False
    count, limit, rolled = i
    if rolled:
        return o is True
    else:
        return o is (count < limit)
